                            testResults.testResult === status ? 'ring-2' : ''
                          }`}
                          style={{
                            background: testResults.testResult === status ? colors.gradient.primary : colors.bg.input,
                            color: testResults.testResult === status ? colors.text.inverse : colors.text.primary,
                            borderColor: testResults.testResult === status ? colors.accent.primary : colors.bg.border,
                            border: `1px solid ${colors.bg.border}`
                          }}
                        >
                          {status}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div>
                    <label className="block text-sm font-semibold mb-2" style={{ color: colors.text.primary }}>Test Notes & Observations</label>
                    <textarea
                      value={testResults.notes}
                      onChange={(e) => setTestResults({ ...testResults, notes: e.target.value })}
                      placeholder="Document your testing procedures, observations, and any exceptions found..."
                      rows={4}
                      className="w-full px-4 py-2.5 rounded-lg outline-none text-sm resize-none"
                      style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                    />
                  </div>

                  {testResults.population && testResults.sampleSize && (
                    <div className="grid grid-cols-3 gap-3 p-4 rounded-lg" style={{ background: colors.bg.input }}>
                      <div>
                        <p className="text-xs" style={{ color: colors.text.muted }}>Exception Rate</p>
                        <p className="text-lg font-bold mt-1" style={{ color: colors.text.primary }}>
                          {testResults.sampleSize > 0 ? ((testResults.exceptionsFound / testResults.sampleSize) * 100).toFixed(1) : 0}%
                        </p>
                      </div>
                      <div>
                        <p className="text-xs" style={{ color: colors.text.muted }}>Sample %</p>
                        <p className="text-lg font-bold mt-1" style={{ color: colors.text.primary }}>
                          {testResults.population > 0 ? ((testResults.sampleSize / testResults.population) * 100).toFixed(1) : 0}%
                        </p>
                      </div>
                      <div>
                        <p className="text-xs" style={{ color: colors.text.muted }}>Projected Exceptions</p>
                        <p className="text-lg font-bold mt-1" style={{ color: colors.text.primary }}>
                          ~{testResults.population > 0 && testResults.sampleSize > 0 
                            ? Math.round((testResults.exceptionsFound / testResults.sampleSize) * testResults.population)
                            : 0}
                        </p>
                      </div>
                    </div>
                  )}
                </>
              ) : (
                <>
                  {/* Qualitative Testing Fields */}
                  <div>
                    <label className="block text-sm font-semibold mb-2" style={{ color: colors.text.primary }}>Testing Approach</label>
                    <select
                      value={testResults.testingApproach}
                      onChange={(e) => setTestResults({ ...testResults, testingApproach: e.target.value })}
                      className="w-full px-4 py-2.5 rounded-lg outline-none text-sm"
                      style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                    >
                      <option>Walkthrough</option>
                      <option>Interview</option>
                      <option>Observation</option>
                      <option>Document Review</option>
                      <option>System Review</option>
                      <option>Process Testing</option>
                      <option>Risk Assessment</option>
                    </select>
                    <p className="text-xs mt-1" style={{ color: colors.text.muted }}>Method used to test the control</p>
                  </div>

                  <div>
                    <label className="block text-sm font-semibold mb-2" style={{ color: colors.text.primary }}>Key Findings & Observations</label>
                    <textarea
                      value={testResults.findings}
                      onChange={(e) => setTestResults({ ...testResults, findings: e.target.value })}
                      placeholder="Document what you observed, tested, or learned about this control..."
                      rows={4}
                      className="w-full px-4 py-2.5 rounded-lg outline-none text-sm resize-none"
                      style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                    />
                  </div>

                  <div>
                    <label className="block text-sm font-semibold mb-2" style={{ color: colors.text.primary }}>Control Conclusion</label>
                    <textarea
                      value={testResults.conclusion}
                      onChange={(e) => setTestResults({ ...testResults, conclusion: e.target.value })}
                      placeholder="Overall assessment and conclusion about control effectiveness..."
                      rows={3}
                      className="w-full px-4 py-2.5 rounded-lg outline-none text-sm resize-none"
                      style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                    />
                  </div>

                  <div>
                    <label className="block text-sm font-semibold mb-2" style={{ color: colors.text.primary }}>Supporting Evidence/References</label>
                    <input
                      type="text"
                      value={testResults.evidence}
                      onChange={(e) => setTestResults({ ...testResults, evidence: e.target.value })}
                      placeholder="e.g., Email threads, system reports, policy documents"
                      className="w-full px-4 py-2.5 rounded-lg outline-none text-sm"
                      style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                    />
                  </div>

                  <div>
                    <label className="block text-sm font-semibold mb-2" style={{ color: colors.text.primary }}>Risk Assessment</label>
                    <div className="grid grid-cols-4 gap-2">
                      {['Low', 'Medium', 'High', 'Critical'].map(risk => (
                        <button
                          key={risk}
                          onClick={() => setTestResults({ ...testResults, riskAssessment: risk })}
                          className={`px-3 py-2 rounded-lg text-sm font-medium transition-all ${
                            testResults.riskAssessment === risk ? 'ring-2' : ''
                          }`}
                          style={{
                            background: testResults.riskAssessment === risk ? colors.gradient.primary : colors.bg.input,
                            color: testResults.riskAssessment === risk ? colors.text.inverse : colors.text.primary,
                            border: `1px solid ${colors.bg.border}`
                          }}
                        >
                          {risk}
                        </button>
                      ))}
                    </div>
                  </div>
                </>
              )}

              {/* Action Buttons */}
              <div className="flex gap-3 pt-4 border-t" style={{ borderColor: colors.bg.border }}>
                <button 
                  onClick={() => setTestingControl(null)}
                  className="flex-1 px-4 py-2.5 rounded-lg font-medium transition-all"
                  style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                >
                  Cancel
                </button>
                <button 
                  onClick={saveTestResults}
                  disabled={testingType === 'quantitative' ? (!testResults.population || !testResults.sampleSize) : (!testResults.findings || !testResults.conclusion)}
                  className="flex-1 px-4 py-2.5 rounded-lg font-medium transition-all hover:scale-105 disabled:opacity-50 flex items-center justify-center gap-2"
                  style={{ background: colors.gradient.primary, color: colors.text.inverse }}
                >
                  <span className="w-4 h-4"><Icons.Check /></span>
                  Save Test Results
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Create New Audit Modal */}
      {showCreateAuditModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-gradient-to-br rounded-2xl shadow-2xl max-w-2xl w-full max-h-[90vh] overflow-auto" style={{ background: colors.bg.dark }}>
            <div className="sticky top-0 p-6 border-b" style={{ background: colors.bg.card, borderColor: colors.bg.border }}>
              <div className="flex items-center justify-between">
                <h2 className="text-2xl font-bold" style={{ color: colors.text.primary }}>Create New Audit</h2>
                <button 
                  onClick={() => setShowCreateAuditModal(false)}
                  className="p-2 rounded-lg transition-all hover:bg-opacity-10"
                  style={{ color: colors.text.muted }}
                >
                  <span className="w-6 h-6"><Icons.X /></span>
                </button>
              </div>
            </div>

            <div className="p-6 space-y-6">
              <div>
                <label className="block text-sm font-semibold mb-2" style={{ color: colors.text.primary }}>Audit Name</label>
                <input
                  type="text"
                  value={newAuditForm.name}
                  onChange={(e) => setNewAuditForm({ ...newAuditForm, name: e.target.value })}
                  placeholder="e.g., Q1 2026 Financial Controls Audit"
                  className="w-full px-4 py-2.5 rounded-lg outline-none text-sm"
                  style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-semibold mb-2" style={{ color: colors.text.primary }}>Country</label>
                  <select
                    value={newAuditForm.country}
                    onChange={(e) => setNewAuditForm({ ...newAuditForm, country: e.target.value })}
                    className="w-full px-4 py-2.5 rounded-lg outline-none text-sm"
                    style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                  >
                    <option value="">Select Country</option>
                    <option>Kenya</option>
                    <option>Nigeria</option>
                    <option>South Africa</option>
                    <option>Global</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-semibold mb-2" style={{ color: colors.text.primary }}>Audit Scope</label>
                  <input
                    type="text"
                    value={newAuditForm.scope}
                    onChange={(e) => setNewAuditForm({ ...newAuditForm, scope: e.target.value })}
                    placeholder="e.g., AP, AR, Treasury"
                    className="w-full px-4 py-2.5 rounded-lg outline-none text-sm"
                    style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                  />
                </div>
              </div>

              <div>
                <div className="flex items-center justify-between mb-4">
                  <label className="block text-sm font-semibold" style={{ color: colors.text.primary }}>Controls to Test</label>
                  <button
                    onClick={addControlRow}
                    className="px-3 py-1.5 rounded-lg text-xs font-medium transition-all hover:scale-105 flex items-center gap-1"
                    style={{ background: colors.gradient.primary, color: colors.text.inverse }}
                  >
                    <span className="w-3 h-3"><Icons.Plus /></span>
                    Add Control
                  </button>
                </div>

                <div className="space-y-3 max-h-64 overflow-y-auto">
                  {auditControls.map((control, idx) => (
                    <div key={idx} className="grid grid-cols-4 gap-3 items-end">
                      <input
                        type="text"
                        value={control.name}
                        onChange={(e) => {
                          const updatedControls = [...auditControls];
                          updatedControls[idx].name = e.target.value;
                          setAuditControls(updatedControls);
                        }}
                        placeholder="Control name"
                        className="px-3 py-2 rounded-lg outline-none text-sm"
                        style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                      />
                      <input
                        type="text"
                        value={control.objective}
                        onChange={(e) => {
                          const updatedControls = [...auditControls];
                          updatedControls[idx].objective = e.target.value;
                          setAuditControls(updatedControls);
                        }}
                        placeholder="Control objective"
                        className="px-3 py-2 rounded-lg outline-none text-sm"
                        style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                      />
                      <select
                        value={control.area}
                        onChange={(e) => {
                          const updatedControls = [...auditControls];
                          updatedControls[idx].area = e.target.value;
                          setAuditControls(updatedControls);
                        }}
                        className="px-3 py-2 rounded-lg outline-none text-sm"
                        style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                      >
                        <option>Finance</option>
                        <option>Treasury</option>
                        <option>IT</option>
                        <option>Procurement</option>
                        <option>Operations</option>
                      </select>
                      <button
                        onClick={() => deleteControlRow(idx)}
                        className="px-3 py-2 rounded-lg text-sm font-medium transition-all hover:bg-opacity-80 flex items-center justify-center"
                        style={{ background: colors.accent.danger, color: colors.text.inverse }}
                        title="Delete this control"
                      >
                        <span className="w-4 h-4"><Icons.Trash /></span>
                      </button>
                    </div>
                  ))}
                </div>
              </div>

              <div className="flex gap-3 pt-6">
                <button
                  onClick={() => setShowCreateAuditModal(false)}
                  className="flex-1 px-4 py-3 rounded-lg font-medium transition-all hover:bg-opacity-80"
                  style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                >
                  Cancel
                </button>
                <button
                  onClick={createNewAudit}
                  className="flex-1 px-4 py-3 rounded-lg font-medium transition-all hover:scale-105"
                  style={{ background: colors.gradient.primary, color: colors.text.inverse }}
                >
                  Create Audit
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Delete Audit Confirmation Modal */}
      {showDeleteConfirm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-gradient-to-br rounded-2xl shadow-2xl max-w-sm w-full" style={{ background: colors.bg.dark }}>
            <div className="p-6">
              <div className="flex items-center justify-center w-12 h-12 mx-auto rounded-full mb-4" style={{ background: 'rgba(239,68,68,0.15)' }}>
                <span className="w-6 h-6" style={{ color: colors.accent.danger }}><Icons.Alert /></span>
              </div>
              <h3 className="text-lg font-bold text-center mb-2" style={{ color: colors.text.primary }}>Delete Audit?</h3>
              <p className="text-center mb-6" style={{ color: colors.text.secondary }}>
                This action cannot be undone. All controls and data for this audit will be permanently deleted.
              </p>
              <div className="flex gap-3">
                <button
                  onClick={() => setShowDeleteConfirm(null)}
                  className="flex-1 px-4 py-3 rounded-lg font-medium transition-all hover:bg-opacity-80"
                  style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                >
                  Cancel
                </button>
                <button
                  onClick={() => deleteAudit(showDeleteConfirm)}
                  className="flex-1 px-4 py-3 rounded-lg font-medium transition-all hover:scale-105"
                  style={{ background: colors.accent.danger, color: colors.text.inverse }}
                >
                  Delete
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Add New User Modal */}
      {showNewUserModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-gradient-to-br rounded-2xl shadow-2xl max-w-md w-full" style={{ background: colors.bg.dark }}>
            <div className="sticky top-0 p-6 border-b" style={{ background: colors.bg.card, borderColor: colors.bg.border }}>
              <div className="flex items-center justify-between">
                <h2 className="text-2xl font-bold" style={{ color: colors.text.primary }}>Add New User</h2>
                <button 
                  onClick={() => setShowNewUserModal(false)}
                  className="p-2 rounded-lg transition-all hover:bg-opacity-10"
                  style={{ color: colors.text.muted }}
                >
                  <span className="w-6 h-6"><Icons.X /></span>
                </button>
              </div>
            </div>

            <div className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-semibold mb-2" style={{ color: colors.text.primary }}>Full Name</label>
                <input
                  type="text"
                  value={newUserForm.name}
                  onChange={(e) => setNewUserForm({ ...newUserForm, name: e.target.value })}
                  placeholder="e.g., Sarah Johnson"
                  className="w-full px-4 py-2.5 rounded-lg outline-none text-sm"
                  style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                />
              </div>

              <div>
                <label className="block text-sm font-semibold mb-2" style={{ color: colors.text.primary }}>Email</label>
                <input
                  type="email"
                  value={newUserForm.email}
                  onChange={(e) => setNewUserForm({ ...newUserForm, email: e.target.value })}
                  placeholder="sarah@mkopa.com"
                  className="w-full px-4 py-2.5 rounded-lg outline-none text-sm"
                  style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                />
              </div>

              <div>
                <label className="block text-sm font-semibold mb-2" style={{ color: colors.text.primary }}>Role</label>
                <select
                  value={newUserForm.role}
                  onChange={(e) => setNewUserForm({ ...newUserForm, role: e.target.value })}
                  className="w-full px-4 py-2.5 rounded-lg outline-none text-sm"
                  style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                >
                  <option>Junior Auditor</option>
                  <option>Senior Auditor</option>
                  <option>Audit Manager</option>
                  <option>Audit Director</option>
                </select>
              </div>

              <div className="flex gap-3 pt-4">
                <button
                  onClick={() => setShowNewUserModal(false)}
                  className="flex-1 px-4 py-3 rounded-lg font-medium transition-all hover:bg-opacity-80"
                  style={{ background: colors.bg.input, color: colors.text.primary, border: `1px solid ${colors.bg.border}` }}
                >
                  Cancel
                </button>
                <button
                  onClick={addNewUser}
                  className="flex-1 px-4 py-3 rounded-lg font-medium transition-all hover:scale-105"
                  style={{ background: colors.gradient.primary, color: colors.text.inverse }}
                >
                  Add User
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Footer */}
      <footer className="px-6 py-3 flex items-center justify-between text-xs" style={{ background: colors.bg.card, borderTop: `1px solid ${colors.bg.border}` }}>
        <div className="flex items-center gap-6" style={{ color: colors.text.muted }}>
          <span><strong style={{ color: colors.accent.success }}>{controls.filter(c => c.Status === 'Done').length}/{controls.length}</strong> Controls</span>
          <span><strong style={{ color: colors.accent.warning }}>{documents.filter(d => d.Status !== 'Done').length}</strong> PBCs Pending</span>
          <span><strong style={{ color: colors.accent.danger }}>{findings.filter(f => f['Risk Rating'] === 'Critical').length}</strong> Critical Findings</span>
        </div>
        <div className="flex items-center gap-2" style={{ color: colors.text.muted }}>
          <span className="w-4 h-4"><Icons.Database /></span>
          <span>Synced with Notion • Last updated: {new Date().toLocaleTimeString()}</span>
        </div>
      </footer>
    </div>
  );
}
